package com.agmsolutions.fabrick_test.controller;import com.agmsolutions.fabrick_test.Model.dto.BalanceDto;import com.agmsolutions.fabrick_test.Model.dto.TransactionDto;import com.agmsolutions.fabrick_test.service.AccountService;import lombok.AllArgsConstructor;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.web.bind.annotation.*;import java.time.LocalDate;import java.util.List;@RestController@RequestMapping("api/account")@AllArgsConstructorpublic class AccountController {    private final AccountService accountService;    @GetMapping("/balance")    public BalanceDto getBalance(@RequestParam(value = "accountId") Long accountId) {        return accountService.getBalance(accountId);    }    @GetMapping("/transactions")    public List<TransactionDto> getTransactions(@RequestParam(value = "accountId") Long accountId,                                                @RequestParam(value = "dateStart") @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate dateStart,                                                @RequestParam(value = "dateEnd") @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate dateEnd) {        return accountService.getTransactions(accountId, dateStart, dateEnd);    }}